  private findProviderDetail(
    providerDetail: IExternalConnectionInfoEvmEIP6963,
  ) {
    const { info } = providerDetail;

    const allProvidersDetail = getEIP6963Providers();
    let providerDetailFound = allProvidersDetail.find(
      (item) => item.info.rdns === info.rdns,
    );

    if (providerDetailFound?.info.uuid !== info.uuid) {
      let detail = allProvidersDetail.find(
        (item) => item.info.uuid === info.uuid && item.info.rdns === info.rdns,
      );
      if (!detail) {
        const uuidOneKeyInjectAsMetamask = '7677b54f-3486-46e2-4e37-bf8747814f';
        detail = allProvidersDetail.find(
          (item) =>
            item.info.uuid !== uuidOneKeyInjectAsMetamask &&
            item.info.rdns === info.rdns,
        );
      }
      providerDetailFound = detail || providerDetailFound;
    }

    return providerDetailFound;
  }

  async providerDetailToConnector(
    providerDetail: IExternalConnectionInfoEvmEIP6963,
  ): Promise<CreateConnectorFn<any>> {
    requestEIP6963Providers();

    let providerDetailFound = this.findProviderDetail(providerDetail);
    if (!providerDetailFound) {
      await waitForDataLoaded({
        data: () => {
          requestEIP6963Providers();
          return this.findProviderDetail(providerDetail);
        },
        logName: 'evm_eip6963_provider_detail',
        wait: 120,
        timeout: 1200,
      }).catch(() => undefined);
      providerDetailFound = this.findProviderDetail(providerDetail);
    }

    const { info } = providerDetail;
    const provider = providerDetailFound?.provider;

    if (!provider) {
      throw new OneKeyLocalError(
        `EVM EIP6963 provider not found: ${info.rdns}`,
      );
    }
    const connectorFn = injected({
      target: {
        ...info,
        id: info.rdns,
        provider,
      },
    });
    return connectorFn;
  }

  // https://github.com/wevm/wagmi/blob/main/packages/core/src/createConfig.ts#L97
  async setup(
    connectorFn: CreateConnectorFn<IExternalWalletProviderEvm>,
    connectionInfo: IExternalConnectionInfo,
  ): Promise<IExternalConnectorEvm> {
    // Set up emitter with uid and add to connector so they are "linked" together.
    const emitter = createEmitter<ConnectorEventMap>(uidForWagmi());

    const { networks: evmNetworks } =
      await this.backgroundApi.serviceNetwork.getNetworksByImpls({
        impls: [IMPL_EVM],
      });
    const chains: Chain[] = evmNetworks.map((item) => {
      const currencyDecimals = item.decimals;
      // const currencyDecimals = NaN;
      if (
        isNil(currencyDecimals) ||
        Number.isNaN(currencyDecimals) ||
        !isNumber(currencyDecimals)
      ) {
        throw new OneKeyLocalError(
          `network (${item.name}) invalid currency decimals: ${currencyDecimals}`,
        );
      }

      return {
        id: Number(item.chainId),
        name: item.name,
        nativeCurrency: {
          name: item.symbol,
          symbol: item.symbol,
          decimals: currencyDecimals,
        },
        rpcUrls: {
          default: {
            http: [],
          },
        },
        // blockExplorers: undefined,
      };
    });

    const innerConnector = connectorFn({
      // @ts-ignore
      emitter,
      chains: chains as unknown as readonly [Chain, ...Chain[]],
      // storage: {} as any,
    });

    const connector: IExternalConnectorEvm = {
      ...innerConnector,
      emitter,
      uid: emitter.uid,
      connectionInfo,
      connect: async (parameters) => {
        if (parameters?.isReconnecting) {
          const isAuthorized = await innerConnector.isAuthorized();
          if (!isAuthorized) {
            const accounts = await innerConnector.getAccounts();
            const chainId = await innerConnector.getChainId();
            // throw new OneKeyLocalError('Wallet is disconnected');
            return {
              accounts,
              chainId,
            };
          }
        }
        return innerConnector.connect(parameters);
      },
    };

    // Start listening for `connect` events on connector setup
    // This allows connectors to "connect" themselves without user interaction (e.g. MetaMask's "Manually connect to current site")
    //
    // emitter.on('connect', this.connect);
    // **** DO NOT add custom event listener: emitter.on('connect', this.connect);
    // because it will cause connector onAccountsChanged not working
    // check details here: https://github.com/wevm/wagmi/blob/main/packages/core/src/connectors/injected.ts#L415

    await connector.setup?.();

    return connector;
  }

  getProviders() {
    requestEIP6963Providers();
    return getEIP6963Providers();
  }

