function isOneKeyExtensionConnection(connectionInfo: IExternalConnectionInfo) {
  const eip6963Rdns =
    connectionInfo.evmEIP6963?.info?.rdns?.toLowerCase() ?? '';
  const eip6963Name =
    connectionInfo.evmEIP6963?.info?.name?.toLowerCase() ?? '';
  const injectedName = connectionInfo.evmInjected?.name?.toLowerCase() ?? '';

  return (
    eip6963Rdns === ONEKEY_EIP6963_RDNS ||
    eip6963Name === 'onekey wallet' ||
    injectedName === 'onekey wallet'
  );
}

export class ExternalControllerEvm extends ExternalControllerBase {
  changeListeners: Record<string, (data: any) => Promise<void>> = {};

  disconnectListeners: Record<string, (data: any) => Promise<void>> = {};

  override removeEventListeners({
    connector,
    accountId,
  }: {
    connector: IExternalConnectorEvm;
    accountId: string | undefined;
  }): void {
    if (accountId) {
      connector.emitter.off('change', this.changeListeners[accountId]);
      connector.emitter.off('disconnect', this.disconnectListeners[accountId]);
      delete this.changeListeners[accountId];
      delete this.disconnectListeners[accountId];
    }
  }

  override addEventListeners({
    connector,
    accountId,
  }: {
    connector: IExternalConnectorEvm;
    accountId: string | undefined;
  }): void {
    this.removeEventListeners({ connector, accountId });

    if (accountId) {
      this.changeListeners[accountId] = async (data: {
        accounts?: readonly `0x${string}`[] | undefined;
        chainId?: number | undefined;
        uid: string;
      }) => {
        console.log('ExternalWalletControllerEvm change event');
        const chainId = await connector.getChainId();
        await this.updateExternalAccountSelectedAddressEvm({
          accountId,
          chainId,
          wagmiConnectorChangeEventParams: data,
        });
      };
      // TODO move disconnectListeners handler to base class
      this.disconnectListeners[accountId] = async (data: any) => {
        console.log('wallet disconnect', data, accountId);
        await this.backgroundApi.serviceDappSide.disconnectExternalWallet({
          accountId,
          account: undefined,
        });
      };
      connector.emitter.on('change', this.changeListeners[accountId]);
      connector.emitter.once('disconnect', this.disconnectListeners[accountId]);
    }
  }

  async updateExternalAccountSelectedAddressEvm({
    accountId,
    chainId,
    wagmiConnectorChangeEventParams,
  }: {
    accountId: string;
    chainId: number;
    wagmiConnectorChangeEventParams: IWagmiConnectorEventMap['change'];
  }) {
    const { accounts } = wagmiConnectorChangeEventParams;
    const usedChainId = wagmiConnectorChangeEventParams.chainId ?? chainId;
    if (accounts && accounts.length && !isNil(usedChainId)) {
      await this.updateAccountAddresses({
        accountId,
        chainId: usedChainId,
        accounts,
      });
    } else if (!isNil(usedChainId)) {
      await this.updateAccountCreateAtNetwork({
        chainId: usedChainId,
        accountId,
      });
    }
  }

  async syncAccountFromPeerWallet(
    payload: IExternalSyncAccountFromPeerWalletPayload,
  ) {
    const connector = payload.connector as IExternalConnectorEvm;
    const { networkId, account } = payload;
    const accounts: `0x${string}`[] = await this.requestAccounts({
      connector,
      networkId,
    });
    const chainId: number = await this.requestChainId({ connector, networkId });

    await this.updateAccountAddresses({
      accountId: account.id,
      chainId,
      accounts,
    });
    if (!accounts?.length) {
      connector.emitter.emit('disconnect');
    }
  }

  _manager: EvmConnectorManager | undefined;

  get manager() {
    if (!this._manager) {
      this._manager = new EvmConnectorManager({
        backgroundApi: this.backgroundApi,
      });
    }
    return this._manager;
  }

  override async listWallets(): Promise<IExternalListWalletsResult> {
    const uuidOneKeyInjectAsMetamask = '7677b54f-3486-46e2-4e37-bf8747814f';
    // const uuidOneKeyInjectAsMetamask = '';
    const allProvidersDetail = this.manager
      .getProviders()
      .filter((item) => item.info.uuid !== uuidOneKeyInjectAsMetamask);

    const icon = externalWalletLogoUtils.getLogoInfo('injected').logo;
    let evmInjectedWallet: IExternalWalletInfo | undefined;
    if (
      platformEnv.isWeb &&
      // @ts-ignore
      global?.[EVM_INJECTED_GLOBAL_VAR]
    ) {
      evmInjectedWallet = {
        name: 'Injected',
        icon,
        connectionInfo: {
          evmInjected: {
            global: EVM_INJECTED_GLOBAL_VAR,
            icon,
            name: 'Injected',
          },
        },
      };
    }

    // return allProvidersDetail;
    const eip6963Wallets: IExternalWalletInfo[] = uniqBy(
      allProvidersDetail,
      (item) => item.info.rdns,
    ).map((item) => ({
      name: item.info.name,
      icon: item.info.icon,
      connectionInfo: {
        evmEIP6963: {
          info: item.info,
        },
      },
    }));

    return {
      wallets: [evmInjectedWallet, ...eip6963Wallets].filter(Boolean),
    };
  }

  override async createConnector({
    connectionInfo,
  }: {
    connectionInfo: IExternalConnectionInfo;
  }): Promise<IExternalCreateConnectorResult> {
    const { evmEIP6963, evmInjected } = connectionInfo;
    let connector: IExternalConnectorEvm | undefined;
    if (evmEIP6963?.info) {
      connector = await ExternalConnectorEvmEIP6963.createConnector({
        manager: this.manager,
        connectionInfo,
      });
    }
    if (evmInjected) {
      connector = await ExternalConnectorEvmInjected.createConnector({
        manager: this.manager,
        connectionInfo,
      });
    }
    if (!connector) {
      throw new OneKeyLocalError('connector is not defined');
    }
    return { connector, connectionInfo };
  }

  private async buildEvmConnectedAddressMap({
    chainId,
    accounts,
  }: {
    chainId: number;
    accounts: readonly `0x${string}`[];
  }) {
    const notSupportedNetworkIds: string[] = [];
    let networkId = `${IMPL_EVM}--${chainId}`;
    const network = await this.backgroundApi.serviceNetwork.getNetworkSafe({
      networkId,
    });
    if (!network) {
      notSupportedNetworkIds.push(networkId);
    }
    // check peer wallet networkId is included in supported networks, otherwise fallback to ETH mainnet
    networkId = network ? networkId : getNetworkIdsMap().eth;
    const addresses = accounts.join(',');
    const addressMap: IDBAccountAddressesMap = {
      // evm can use impl for all sub networks
      [networkId]: addresses,
      [IMPL_EVM]: addresses,
    };
    const impl = IMPL_EVM;
    const createAtNetwork = networkId;
    // networkIds = [networkId]; // limit account can only use these networks
    return {
      impl,
      createAtNetwork,
      addressMap,
      networkId,
      notSupportedNetworkIds,
    };
  }

  override async connectWallet({
    connector,
    connectToWalletOptions,
  }: {
    connector: IExternalConnectorEvm;
    connectToWalletOptions?: IConnectToWalletOptions;
  }): Promise<IExternalConnectWalletResult> {
    const { connectionInfo } = connector;
    checkIsDefined(connectionInfo);
    const requestOneKeyKeylessAccount = isOneKeyExtensionConnection(
      connectionInfo,
    )
      ? connectToWalletOptions?.webKeylessPendingLogin?.provider
      : undefined;
    const result = (await connector.connect(
      (requestOneKeyKeylessAccount
        ? { requestOneKeyKeylessAccount }
        : {}) as any,
    )) as IExternalConnectResultEvm;

    if (!result?.accounts?.length) {
      throw new OneKeyLocalError('No authorized external wallet accounts');
    }

    const { impl, createAtNetwork, addressMap, notSupportedNetworkIds } =
      await this.buildEvmConnectedAddressMap(result);
    let name = '';
    if (connectionInfo?.evmInjected?.name) {
      name = connectionInfo?.evmInjected?.name;
    }
    if (connectionInfo?.evmEIP6963?.info?.name) {
      name = connectionInfo?.evmEIP6963?.info?.name;
    }
    return {
      connectionInfo,
      accountInfo: {
        impl,
        createAtNetwork,
        addresses: addressMap,
        networkIds: undefined,
        name: name || '',
      },
      notSupportedNetworkIds,
    };
  }

  override async signMessageByWalletConnect(
    payload: IExternalSignMessageByWalletConnectPayload,
  ): Promise<ISignedMessagePro> {
    const { params, networkId, connector, account } = payload;

    const wcChain = await this.getWcChain({ networkId });
    const { method, callParams } = evmConnectorUtils.parseSignMessageParams({
      params,
    });
    const provider = await connector.getProvider();
    if (!wcChain) {
      throw new OneKeyLocalError(
        'evmWalletConnect signMessage ERROR: wcChain not found',
      );
    }
    const result = await provider.request<string>({
      args: {
        method,
        params: callParams,
      },
      wcChain,
      account,
    });

    return [result];
  }

  override async sendTransactionByWalletConnect(
    payload: IExternalSendTransactionByWalletConnectPayload,
  ): Promise<ISignedTxPro> {
    const { params, networkId, connector, account } = payload;

    const wcChain = await this.getWcChain({ networkId });
    const { method, callParams } = evmConnectorUtils.parseSendTransactionParams(
      {
        params,
      },
    );
    const provider = await connector.getProvider();
    if (!wcChain) {
      throw new OneKeyLocalError(
        'evmWalletConnect sendTransaction ERROR: wcChain not found',
      );
    }
    const txid = await provider.request<string>({
      args: {
        method,
        params: callParams,
      },
      wcChain,
      account,
    });

    if (!txid) {
      throw new OneKeyLocalError(
        'walletConnect sendTransaction ERROR: txid not found',
      );
    }

    return {
      txid,
      rawTx: '',
      encodedTx: params.unsignedTx.encodedTx,
    };
  }

  override async handleWalletConnectEvents(
    params: IExternalHandleWalletConnectEventsParams,
  ): Promise<void> {
    const { eventData, eventName, account, wcChainInfo } = params;

    // handle accountsChanged
    if (eventName === 'accountsChanged') {
      // const wcSessionEvent = {
      //   'id': 1710226817544891,
      //   'topic':
      //     '7452725652a616ebc2554ee049b026d56f537177c969fe5c07f92f75ee5e8bb6',
      //   'params': {
      //     'event': {
      //       'name': 'accountsChanged',
      //       'data': ['eip155:137:0x111'],
      //     },
      //     'chainId': 'eip155:137',
      //   },
      // };

      if (wcChainInfo && account) {
        const { isMergedNetwork, networkIdOrImpl } =
          accountUtils.getWalletConnectMergedNetwork({
            networkId: wcChainInfo.networkId,
          });
        const impl = networkUtils.getNetworkImpl({
          networkId: wcChainInfo.networkId,
        });
        const addresses =
          account.connectedAddresses[networkIdOrImpl]
            .split(',')
            .filter(Boolean) || [];
        const eventAddress = (eventData as string[] | undefined)?.[0];
        if (eventAddress && isString(eventAddress)) {
          const result =
            this.backgroundApi.serviceWalletConnect.parseWalletConnectFullAddress(
              {
                wcAddress: eventAddress,
              },
            );
          const addressIndex = addresses.indexOf(result.address);
          if (addressIndex >= 0) {
            const selectedMapNew = {
              ...account.selectedAddress,
              [networkIdOrImpl]: addressIndex,
            };
            if (isMergedNetwork) {
              // walletconnect always use impl to find compatible network if isMergedNetwork=true
              delete selectedMapNew[wcChainInfo.networkId];
            } else {
              delete selectedMapNew[impl];
            }
            await localDb.updateExternalAccount({
              accountId: account.id,
              selectedMap: selectedMapNew,
            });
            appEventBus.emit(EAppEventBusNames.AccountUpdate, undefined);
          }
        }
      }
    }

    // handle chainChanged
    if (eventName === 'chainChanged') {
      // const wcSessionEvent = {
      //   'id': 1710226674065096,
      //   'topic':
      //     '7452725652a616ebc2554ee049b026d56f537177c969fe5c07f92f75ee5e8bb6',
      //   'params': {
      //     'event': { 'name': 'chainChanged', 'data': 137 },
      //     'chainId': 'eip155:137',
      //   },
      // };
      await this.updateAccountCreateAtNetwork({
        chainId: eventData as number,
        accountId: account.id,
      });
    }
  }

  async updateAccountAddresses({
    accountId,
    chainId,
    accounts,
  }: {
    accountId: string;
    chainId: number;
    accounts: readonly `0x${string}`[];
  }) {
    // emit disconnect event
    if (!accounts?.length) {
      return;
    }
    const { addressMap, createAtNetwork } =
      await this.buildEvmConnectedAddressMap({
        chainId,
        accounts: accounts as any,
      });
    await localDb.updateExternalAccount({
      accountId,
      addressMap,
      createAtNetwork,
    });
    appEventBus.emit(EAppEventBusNames.AccountUpdate, undefined);
  }

  async updateAccountCreateAtNetwork({
    accountId,
    chainId,
  }: {
    accountId: string | undefined;
    chainId: string | number;
  }) {
    const newNetworkId = `evm--${chainId}`;
    const network = await this.backgroundApi.serviceNetwork.getNetworkSafe({
      networkId: newNetworkId,
    });
    if (network && accountId) {
      await localDb.updateExternalAccount({
        accountId,
        createAtNetwork: network.id,
      });
      appEventBus.emit(EAppEventBusNames.AccountUpdate, undefined);
    }
  }

  override async sendTransaction(
    payload: IExternalSendTransactionPayload,
  ): Promise<ISignedTxPro> {
    const { params } = payload;
    const connector = payload.connector as IExternalConnectorEvm;
    const { method, callParams } = evmConnectorUtils.parseSendTransactionParams(
      {
        params,
      },
    );
    // TODO check isAuthorized, check address matched, check network matched and request chain switch
    const provider = await connector.getProvider();
    const txid = await provider.request({
      method,
      params: callParams as any,
    });

    if (!txid) {
      throw new OneKeyLocalError(
        'ExternalWalletControllerEvm sendTransaction ERROR: txid not found',
      );
    }

    return {
      txid,
      rawTx: '',
      encodedTx: params.unsignedTx.encodedTx,
    };
  }

  override async signMessage(
    payload: IExternalSignMessagePayload,
  ): Promise<ISignedMessagePro> {
    const { params } = payload;
    const connector = payload.connector as IExternalConnectorEvm;
    const { method, callParams } = evmConnectorUtils.parseSignMessageParams({
      params,
    });
    const provider = await connector.getProvider();
    // TODO check address or network matched
    const result = await provider.request({
      // @ts-ignore
      method,
      params: callParams,
    });

    // @ts-ignore
    return [result];
  }

  async requestChainId({
    connector,
    networkId,
  }: {
    connector: IExternalConnectorEvm;
    networkId: string;
  }): Promise<number> {
    const provider = await connector.getProvider();
    const walletConnectProvider =
      provider instanceof WalletConnectDappSideProvider ? provider : undefined;

    if (walletConnectProvider) {
      const wcChain = await this.getWcChain({ networkId });
      const chainIdNumOrHexString = await walletConnectProvider.request({
        args: {
          method: 'eth_chainId',
        },
        wcChain,
        account: undefined,
      });
      return new BigNumber(chainIdNumOrHexString as string).toNumber();
    }

    const chainIdNumOrHexString = await provider.request({
      method: 'eth_chainId',
    });
    return new BigNumber(chainIdNumOrHexString).toNumber();
  }

  async requestAccounts({
    connector,
    networkId,
  }: {
    connector: IExternalConnectorEvm;
    networkId: string;
  }): Promise<`0x${string}`[]> {
    const provider = await connector.getProvider();
    const walletConnectProvider =
      provider instanceof WalletConnectDappSideProvider ? provider : undefined;

    let addresses: `0x${string}`[] = [];
    if (walletConnectProvider) {
      const wcChain = await this.getWcChain({ networkId });
      addresses = await walletConnectProvider.request({
        args: {
          method: 'eth_accounts',
        },
        wcChain,
        account: undefined,
      });
    } else {
      addresses = await provider.request({
        method: 'eth_accounts',
      });
    }

    return addresses.map((address) =>
      (address || '')?.toLowerCase(),
    ) as `0x${string}`[];
  }

  override async checkNetworkOrAddressMatched(
    payload: IExternalCheckNetworkOrAddressMatchedPayload,
  ): Promise<void> {
    const { account, networkId } = payload;

    const connector = payload.connector as IExternalConnectorEvm;
    const peerAddresses = await this.requestAccounts({ connector, networkId });

    if (
      !peerAddresses.includes((account.address || '')?.toLowerCase() as any)
    ) {
      throw new OneKeyLocalError(
        `${appLocale.intl.formatMessage({
          id: ETranslations.feedback_address_not_matched,
        })}: ${networkId} ${account.address}`,
      );
    }

    /*
    // walletconnect does not need to check if chainId matches
    // because wcChain has been passed in request()
    // and OKX wallet will not return the correct chainId
    */
    const chainId = networkUtils.getNetworkChainId({ networkId });
    const isWalletConnect =
      payload.connector instanceof ExternalConnectorWalletConnect;
    const peerChainIdNum = await this.requestChainId({ connector, networkId });

    if (!isWalletConnect && chainId !== peerChainIdNum.toString()) {
      // throw new OneKeyLocalError(
      //   `${appLocale.intl.formatMessage({
      //     id: ETranslations.global_network_not_matched,
      //   })}: expected=${chainId} received=${peerChainIdNum}`,
      // );
      // switch chain to the correct chainId, metamask no longer returns chainId of wallet homepage
      const network = await this.backgroundApi.serviceNetwork.getNetworkSafe({
        networkId,
      });
      const customRpc =
        await this.backgroundApi.serviceCustomRpc.getCustomRpcForNetwork(
          networkId,
        );
      // ethereum.request({method: 'wallet_switchEthereumChain', params: []})
      await connector?.switchChain?.({
        // ethereum.request({method: 'wallet_addEthereumChain', params: []})
        addEthereumChainParameter: {
          // chainId: Number(chainId),
          chainName:
            network?.name || network?.shortname || network?.shortcode || '',
          // nativeCurrency: {
          //   name: network?.symbol || '',
          //   symbol: network?.symbol || '',
          //   // TODO do not hardcode 18, throw error if decimals not valid
          //   // decimals: network?.decimals,
          // },
          get nativeCurrency():
            | { name: string; symbol: string; decimals: number }
            | undefined {
            throw new OneKeyLocalError(
              `${appLocale.intl.formatMessage({
                id: ETranslations.feedback_external_wallet_does_not_approve_network,
              })}: ${network?.name || network?.shortname || networkId}`,
            );
          },
          rpcUrls: customRpc?.rpc ? [customRpc.rpc] : [],
          blockExplorerUrls: [network?.explorerURL]?.filter(Boolean) || [],
          iconUrls: [network?.logoURI]?.filter(Boolean) || [],
        },
        chainId: Number(chainId),
      });
    }
  }
}
